/// <remarks><para>The last element of the returned vector is less than or equal to <paramref name="end" />.</para><para><see cref="M:ILNumerics.Core.Functions.Builtin.MathInternal.arange(System.Double,System.Double)" /> can not create empty vectors! Use <see cref="M:ILNumerics.Core.Functions.Builtin.MathInternal.empty``1(System.Int64,System.Int64,ILNumerics.StorageOrders)" />, <see cref="M:ILNumerics.Core.Functions.Builtin.MathInternal.zeros``1(System.Int64,System.Int64,ILNumerics.StorageOrders)" />, <see cref="M:ILNumerics.Core.Functions.Builtin.MathInternal.array``1(``0,System.Int64,ILNumerics.StorageOrders)" /> or the like to create empty arrays.</para></remarks>
