/// <summary>
/// Creates a new ILNumerics array with regularly spaced element values.
/// </summary>
/// <typeparam name="T">Element type.</typeparam>
/// <param name="start">The start value for the new elements.</param>
/// <param name="step">The step size value for the new elements.</param>
/// <param name="size">Dimension lengths as vector.</param>
/// <param name="order">[Optional] The storage order for the new array. Default: <see cref="F:ILNumerics.StorageOrders.ColumnMajor" />.</param>
/// <returns>New ILNumerics array initialized with linearly spaced elements according to <paramref name="start" /> and counting up/downwards by <paramref name="step" /> along the storage order.</returns>
/// <remarks><para>The <see cref="M:ILNumerics.Core.Functions.Builtin.MathInternal.counter``1(``0,``0,ILNumerics.InArray{System.Int64},ILNumerics.StorageOrders)" /> function and the corresponding
/// overloads for providing individual dimension length parameters <see cref="M:ILNumerics.Core.Functions.Builtin.MathInternal.counter``1(``0,``0,System.Int64,ILNumerics.StorageOrders)" />,...
/// create n-dimensional numeric arrays with automatically generated values based on a given <paramref name="start" /> value and a <paramref name="step" /> value.
/// The size of the new array is determined by the <paramref name="size" /> parameter(s). The firsts element value is assigned
/// the <paramref name="start" /> value. Subsequent values are computed by adding the value of <paramref name="step" /> to each elements predecessor.</para><para>The term 'predecessor' here means: the predecessor E0 of element E1 is the element having an index I(E0) of I(E1) - 1,
/// where the index I() corresponds to the storage location of the element in memory, relative to the first element.</para><para>The storage order is determined by <paramref name="order" />. By default, elements are lined up in memory
/// in column major storage order. <paramref name="order" /> must be one out of <see cref="F:ILNumerics.StorageOrders.ColumnMajor" />
/// or <see cref="F:ILNumerics.StorageOrders.RowMajor" />. Note, how the storage order affects the order of values in the new array.</para></remarks>
/// <example><para>Creating a new array of size [4,3], filled with upwards counting values, starting at 1.</para><code><![CDATA[Array<double> A = counter<double>(1, 1, 4, 3);
/// //<Double> [4,3] 1...12 |
/// //    [0]:           1          5          9
/// //    [1]:           2          6         10
/// //    [2]:           3          7         11
/// //    [3]:           4          8         12]]></code><para>Creating a new array of size [4,3,2] of ushort values: </para><code><![CDATA[counter<sbyte>(10, -10, 4,3,2)
/// //<SByte> [4,3] 1...12 |
/// //    [0]: (:,:,0)
/// //    [1]:    10  -30  -70
/// //    [2]:     0  -40  -80
/// //    [3]:   -10  -50  -90
/// //    [4]:   -20  -60 -100
/// //    [5]: (:,:,1)
/// //    [6]:  -110  106   66
/// //    [7]:  -120   96   56
/// //    [8]:   126   86   46
/// //    [9]:   116   76   36]]></code><para>Note, how the computed values of data type 'sbyte' wrap around at the limits of 'sbyte'
/// without notice!</para><para>Creating a new array of size [4,3] with upwards counting values in row major order: </para><code><![CDATA[counter<float>(1, 1, 4,3, StorageOrders.RowMajor)
/// //<Single> [4,3] 1...12 -
/// //    [0]:           1          2          3
/// //    [1]:           4          5          6
/// //    [2]:           7          8          9
/// //    [3]:          10         11         12
/// //]]></code></example>
public static Array<T> counter<T>(T start, T step, InArray<Int64> size, StorageOrders order = StorageOrders.ColumnMajor) where T : struct, IEquatable<T>, IConvertible { return ILNumerics.Core.Functions.Builtin.MathInternal.counter<T>(start, step, size, order);}
