public static void csvwrite<T>(InArray<T> A, String filename, Func<T,String> elementConverter = null, String elementSeparator = ",", CultureInfo culture = null, Encoding encoding = null) {  ILNumerics.Core.Functions.Builtin.MathInternal.csvwrite<T>(A, filename, elementConverter, elementSeparator, culture, encoding);}
