/// <returns>Square matrix filled with random numbers.</returns>
/// <remarks><para>Values range from 0.0 to 1.0, uniformly distributed.</para><para>If the optional argument <paramref name="order" /> is omitted ILNumerics is free to decide for the storage order. Often, an advantageous
/// (in terms of processing performance) storage order is selected according to the current algorithmic context, to the current setting of <see cref="P:ILNumerics.Settings.ArrayStyle" />
/// and other factors.</para></remarks>
public static Array<Double> rand(Int64 d0, StorageOrders order = StorageOrders.ColumnMajor) { return ILNumerics.Core.Functions.Builtin.MathInternal.rand(d0, order);}
