/// must be of the same size or be broadcastable to each other. All arrays returned are of the broadcasted size.</remarks>
public static Array<Double> sphere2cart(InArray<Double> radius, InArray<Double> theta, InArray<Double> phi, OutArray<Double> Y = null, OutArray<Double> Z = null) { return ILNumerics.Core.Functions.Builtin.MathInternal.sphere2cart(radius, theta, phi, Y, Z);}
